### 洛谷P3384
[P3384 【模板】重链剖分/树链剖分](https://www.luogu.com.cn/problem/P3384)

用线段树维护重链剖分后的链的权值。

```cpp
#include<bits/stdc++.h>
typedef int int32;
#define int long long
using namespace std;
const int N = 5e5 + 5;
int n, m, root, mod, a[N], size[N], dep[N], fa[N], top[N], son[N], dfn[N],
rdfn[N], id[N], tree[N << 2], tag[N << 2], cnt;
vector<pair<int,int>>nbr[N];
void pushup(int x)
{
	tree[x] = tree[x << 1] + tree[x << 1 | 1];
	return;
}
void addtag(int x, int l, int r, int val)
{
	tag[x] += val;
	tree[x] += (r - l + 1) * val;
	return;
}
void pushdown(int x, int l, int r)
{
	if (!tag[x])
		return;
	int mid = (l + r) >> 1;
	addtag(x << 1, l, mid, tag[x]);
	addtag(x << 1 | 1, mid + 1, r, tag[x]);
	tag[x] = 0;
	return;
}
void build(int x, int l, int r)
{
	if (l == r)
	{
		tree[x] = a[id[l]]; // 不要写成 `tree[x] = a[l]`！
		return;
	}
	int mid = (l + r) >> 1;
	build(x << 1, l, mid);
	build(x << 1 | 1, mid + 1, r);
	pushup(x);
	return;
}
void update(int x, int l, int r, int qx, int qy, int val)
{
	if (qy < l || qx > r)
		return;
	if (qx <= l && qy >= r)
	{
		addtag(x, l, r, val);
		return;
	}
	int mid = (l + r) >> 1;
	pushdown(x, l, r);
	update(x << 1, l, mid, qx, qy, val);
	update(x << 1 | 1, mid + 1, r, qx, qy, val);
	pushup(x);
	return;
}
int query(int x, int l, int r, int qx, int qy)
{
	if (qy < l || qx > r)
		return 0;
	if (qx <= l && qy >= r)
		return tree[x];
	int mid = (l + r) >> 1;
	pushdown(x, l, r);
	return query(x << 1, l, mid, qx, qy) + query(x << 1 | 1, mid + 1, r, qx, qy);
}
void dfs(int x, int fa)
{
	int maxi = 0;
	::size[x] = 1;
	dep[x] = dep[fa] + 1;
	::fa[x] = fa;
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (nxt != fa)
		{
			dfs(nxt, x);
			::size[x] += ::size[nxt];
			if (::size[nxt] > maxi)
				son[x] = nxt, maxi = ::size[nxt];
		}
	}
	return;
}
void dfs1(int x, int fa)
{
	dfn[x] = ++cnt;
	id[cnt] = x;
	if (son[x])
	{
		top[son[x]] = top[x];
		dfs1(son[x], x);
	}
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if(nxt != fa && !top[nxt])
		{
			top[nxt] = nxt;
			dfs1(nxt, x);
		}
	}
	rdfn[x] = cnt;
	return;
}
int lca(int x, int y)
{
	while (top[x] != top[y])
	{
		if (dep[top[x]] > dep[top[y]])
			x = fa[top[x]];
		else
			y = fa[top[y]];
	}
	return dep[x] < dep[y] ? x : y;
}
void update_path(int x, int y, int val)
{
	while (top[x] != top[y])
	{
		if (dep[top[x]] > dep[top[y]])
		{
			update(1, 1, n, dfn[top[x]], dfn[x], val);
			x = fa[top[x]];
		}
		else
		{
			update(1, 1, n, dfn[top[y]], dfn[y], val);
			y = fa[top[y]];
		}
	}
	if (dep[x] > dep[y])
		swap(x,y);
	update(1, 1, n, dfn[x], dfn[y], val);
	return;
}
int query_path(int x, int y)
{
	int sum = 0;
	while (top[x] != top[y])
	{
		if (dep[top[x]] > dep[top[y]])
		{
			sum += query(1, 1, n, dfn[top[x]], dfn[x]);
			x = fa[top[x]];
		}
		else
		{
			sum += query(1, 1, n, dfn[top[y]], dfn[y]);
			y = fa[top[y]];
		}
	}
	if (dep[x] > dep[y])
		swap(x,y);
	return sum + query(1, 1, n, dfn[x], dfn[y]);
}
signed main()
{
	ios::sync_with_stdio(0);
	cin.tie(0), cout.tie(0);
	cin >> n >> m >> root >> mod;
	for (int i = 1; i <= n; i++)
		cin >> a[i], a[i] %= mod;
	for (int i = 1; i < n; i++)
