void pushup(int x)
{
	tree[x] = tree[x << 1] + tree[x << 1 | 1];
	return;
}
void addtag(int x, int l, int r, node1 val)
{
	tag[x] += val;
	tree[x] += val;
	return;
}
void pushdown(int x, int l, int r)
{
	if (!tag[x])
		return;
	int mid = (l + r) >> 1;
	addtag(x << 1, l, mid, tag[x]);
	addtag(x << 1 | 1, mid + 1, r, tag[x]);
	tag[x] = { 0,0 };
	return;
}
void build(int x, int l, int r)
{
	if (l == r)
	{
		tree[x] = { a[id[l]],a[id[l]],1 };
		return;
	}
	int mid = (l + r) >> 1;
	build(x << 1, l, mid);
	build(x << 1 | 1, mid + 1, r);
	pushup(x);
	return;
}
void update(int x, int l, int r, int qx, int qy, node1 val)
{
	if (qy < l || qx > r)
		return;
	if (qx <= l && qy >= r)
	{
		addtag(x, l, r, val);
		return;
	}
	int mid = (l + r) >> 1;
	pushdown(x, l, r);
	update(x << 1, l, mid, qx, qy, val);
	update(x << 1 | 1, mid + 1, r, qx, qy, val);
	pushup(x);
	return;
}
node query(int x, int l, int r, int qx, int qy)
{
	if (qy < l || qx > r)
		return { 0,(int)-1e9,0 };
	if (qx <= l && qy >= r)
		return tree[x];
	int mid = (l + r) >> 1;
	pushdown(x, l, r);
	return query(x << 1, l, mid, qx, qy) +
		query(x << 1 | 1, mid + 1, r, qx, qy);
}
void dfs(int x, int fa)
